package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testGetAutoFlush_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.getAutoFlush());
    }

    @Test
    void testGetAutoFlush_CustomFalse() throws Exception {
        // Create CSVFormat instance with autoFlush = false using reflection to invoke private constructor
        CSVFormat format = createCSVFormatWithAutoFlush(false);
        assertFalse(format.getAutoFlush());
    }

    @Test
    void testGetAutoFlush_CustomTrue() throws Exception {
        CSVFormat format = createCSVFormatWithAutoFlush(true);
        assertTrue(format.getAutoFlush());
    }

    private CSVFormat createCSVFormatWithAutoFlush(boolean autoFlush) throws Exception {
        // Use reflection to access the private constructor
        Class<CSVFormat> clazz = CSVFormat.class;
        java.lang.reflect.Constructor<CSVFormat> constructor = clazz.getDeclaredConstructor(
                char.class, Character.class, CSVFormat.QuoteMode.class, Character.class, Character.class, boolean.class,
                boolean.class, String.class, String.class, Object[].class, String[].class, boolean.class, boolean.class,
                boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        return constructor.newInstance(
                ',', // delimiter
                '"', // quoteChar
                null, // quoteMode
                null, // commentStart
                null, // escape
                false, // ignoreSurroundingSpaces
                false, // ignoreEmptyLines
                "\n", // recordSeparator
                null, // nullString
                null, // headerComments
                null, // header
                false, // skipHeaderRecord
                false, // allowMissingColumnNames
                false, // ignoreHeaderCase
                false, // trim
                false, // trailingDelimiter
                autoFlush // autoFlush
        );
    }
}
